export const 鎮宅招金 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.34 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：頂桿＋左右圈柱＋中菱＋右內圈杙
    線(p => p.M(X(0.9), Z(1.2)).L(X(6.7), Z(1.1)));
    圈(0.6, 1.2);
    圈(7.0, 1.1);
    for (const z of [2.2, 3.6, 5.0, 6.4, 7.7])
        圈(0.4, z);
    for (const z of [2.2, 3.5, 4.9, 6.3, 7.6])
        圈(7.0, z);
    圈(3.0, 2.9);
    圈(1.6, 4.6);
    圈(4.4, 4.6);
    圈(3.0, 6.3);
    連([3.0, 2.9], [1.6, 4.6]);
    連([3.0, 2.9], [4.4, 4.6]);
    連([1.6, 4.6], [3.0, 6.3]);
    連([4.4, 4.6], [3.0, 6.3]);
    for (const z of [3.3, 4.6, 5.9])
        圈(5.6, z);
    連([5.6, 3.3], [5.6, 4.6]);
    連([5.6, 4.6], [5.6, 5.9]);
    // 寬匣桁
    線(p => p.M(X(0.7), Z(8.6)).L(X(0.7), Z(11.6)).L(X(7.2), Z(11.5))
        .L(X(7.2), Z(8.5)).L(X(0.65), Z(8.6)), 0.42);
    線(p => p.M(X(0.8), Z(10.1)).L(X(7.1), Z(10.0)));
    // 左目梯（四箱）
    線(p => p.M(X(0.8), Z(12.0)).L(X(0.8), Z(17.5)));
    線(p => p.M(X(3.4), Z(11.95)).L(X(3.4), Z(17.45)));
    for (let i = 0; i <= 4; i++)
        線(p => p.M(X(0.8), Z(12.0 + i * 1.375)).L(X(3.4), Z(11.95 + i * 1.375)));
    // 右干柱雙軌（貫豎＋橫杙＋側軌）
    線(p => p.M(X(5.2), Z(11.8)).L(X(5.2), Z(17.5)));
    線(p => p.M(X(4.4), Z(12.4)).L(X(6.2), Z(12.3)));
    線(p => p.M(X(6.2), Z(12.5)).L(X(6.2), Z(17.3)));
    // 張脚
    線(p => p.M(X(0.9), Z(17.8)).C(X(0.7), Z(18.5), X(0.6), Z(19.0), X(0.6), Z(19.4)));
    線(p => p.M(X(3.3), Z(17.7)).C(X(3.4), Z(18.4), X(3.4), Z(18.9), X(3.3), Z(19.3)));
    線(p => p.M(X(5.2), Z(17.7)).C(X(5.1), Z(18.4), X(5.0), Z(18.9), X(4.9), Z(19.3)));
    線(p => p.M(X(6.2), Z(17.5)).C(X(6.4), Z(18.2), X(6.5), Z(18.8), X(6.5), Z(19.2)));
};
